import pickle
import os

class UserPreferences:
    def __init__(self, name, preferences):
        self.name = name
        self.preferences = preferences
        
def save_user_preferences(file_path, user_preference_object):
    with open(file_path, 'wb') as f:
        pickle.dump(user_preference_object, f)

def load_user_preferences(file_path):
    if os.path.exists(file_path):  # check if the file exists
        with open(file_path, 'rb') as f:
            return pickle.load(f)
    else:
        print("File not found")

# Creating an object of UserPreferences class and saving it to a file
user_prefs = UserPreferences('John', {'key1':'value1', 'key2':['list', 'elem']})  # custom object also includes nested data like dictionaries, lists etc.
save_user_preferences('/path/to/file.pickle', user_prefs)

# Loading the saved preference from file to another object
loaded_object = load_user_preferences('/path/to/file.pickle')